      "1x3d9ab": "Cookie/Armazenamento", "bz8wpf": "Finalidade", "ykgwdn": "Duração",
      "1ydxuz6": "Mantém você conectado à sua conta PollSlide",
      "6cbtx6": "Sessão / persistente (armazenamento local)",
